SELECT TOP 1 [TAG_ID], SUM(TS.[DAILY_SEARCHES]) AS TOTAL_SEARCHES 
FROM [TAG_STATISTICS] TS 
WHERE TS.[IsDeleted] = 0 
	AND TS.[STATISTICS_DATE] > DATEADD(DAY, -1,
	GETDATE()) 
GROUP BY TS.[TAG_ID] 
ORDER BY TS.[TOTAL_SEARCHES] DESC 